async function seedModule1Questions() {
  try {
    await mongoose.connect(process.env.MONGODB_URI);
    console.log('Connected to MongoDB');

    const module = await Module.findOne({ title: 'Module 1: Introduction to Computers' });
    if (!module) {
      console.log('Module "Introduction to Computers" not found');
      process.exit(1);
    }

    await AssignmentQuestion.deleteMany({ moduleId: module._id });
    console.log('Cleared existing questions');

    const setA = JSON.parse(setAJSON);
    const setB = JSON.parse(setBJSON);
    const setC = JSON.parse(setCJSON);

    const allQuestions = [...setA, ...setB, ...setC].map(q => ({
      ...q,
      moduleId: module._id
    }));

    await AssignmentQuestion.insertMany(allQuestions);
    console.log(`✅ Successfully seeded ${allQuestions.length} questions for Module 1`);

    process.exit(0);
  } catch (error) {
    console.error('Seeding error:', error);
    process.exit(1);
  }
}

seedModule1Questions();